import{_ as o,r,o as i,c,b as e,d as t,e as n,a as s}from"./app-2a089349.js";const l={},p=s('<h1 id="setting-up-stripe-success-cancel-payment-already-subscribed-customer-portal-stripe-checkout-url-and-embedded-checkout-pages" tabindex="-1"><a class="header-anchor" href="#setting-up-stripe-success-cancel-payment-already-subscribed-customer-portal-stripe-checkout-url-and-embedded-checkout-pages" aria-hidden="true">#</a> Setting up Stripe Success, Cancel Payment, Already Subscribed,Customer Portal,Stripe Checkout URL and Embedded Checkout Pages</h1><p>Once you have installed the Stripe extension on your WordPress website, a notification will appear on the top of your wp-admin page. This notification will indicate which pages need to be created. To create the required pages, simply click on the <strong>&quot;Create Pages&quot;</strong> button. Once you have completed this step, the Stripe Pages, including the <strong>Success, Cancel, Already Subscribed,</strong> <strong>Stripe Checkout URL</strong> and <strong>Customer Portal</strong> pages will automatically be assigned to the page settings.</p><p><strong>Note:</strong> If the &#39;create pages&#39; button did not automatically generate the pages, you can create them manually. Refer to this article for guidance: <a href="/docs-v3/um-stripe/article/1900-how-to-create-stripe-pages-manually">How to Create Stripe Pages Manually</a> .</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b427cd20e3b82eb738e083/file-7jSHQalUOk.png" alt=""></p><p>Go to <strong>wp-admin&gt; Pages</strong> to check if the pages are successfully created.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b42bf720e3b82eb738e088/file-UtaEU5Er7V.png" alt=""></p><p>When a user attempts to subscribe and is then redirected to the Stripe Checkout page, there are three pages the user will be redirected to:</p>',7),h=s('<li><strong>Payment Successful Page</strong> - The user will be redirected to this page when the payment is successful, and completed, or the subscription starts trialing. The default content of this page is a <a href="/docs-v3/um-stripe/article/1616-stripe-shortcodes-reference">shortcode</a> that displays the user&#39;s order details. For members who subscribe to a plan via the Register form, you must <a href="/docs-v3/um-stripe/article/1634-stripe---add-subscription-plans-to-a-registeration-form">set the Success page URL</a> in the <strong>User Role settings &gt; Register options</strong>. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b4b7b052a6af5def3c8e66/file-bHOA3iv42J.png" alt=""></li><li><strong>Payment Canceled Page</strong> - The user will be redirected to this page when a user clicks on the logo of your store or the back button on the Stripe Checkout Page. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b4bd8520e3b82eb738e0c9/file-D0mTdlYLSp.png" alt=""> <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b4bd9430c1875e8e067574/file-pr0H6RPn4r.png" alt=""></li><li><strong>Already Subscribed Page</strong> - This page is a landing page when a user tries to subscribe with a direct Subscribe URL but they are already subscribed, so they will be redirected to this page. The default content of this page is a message that the user already has a subscription and a shortcode that displays a customer portal button that links to the Stripe customer portal site<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b4c3ce270765339befc754/file-TzQUi34P6o.png" alt=""></li><li><strong>Stripe Checkout URL -</strong>This page is designated for the checkout URL that is created or generated after you&#39;ve created or imported pricing information for a specific plan.</li>',4),d=e("strong",null,"Customer Portal -",-1),u={href:"http://yoursite.com/customer-portal/",target:"_blank",rel:"noopener noreferrer"},g=e("a",{href:"/docs-v3/um-stripe/article/1894-how-to-access-the-stripe-customer-portal-from-the-website"},"article",-1),m=s('<p>To set the Success, Canceled, Already Subscribed, Stripe Checkout URL Pages and Customer Portal, go to <strong>WP Admin &gt; Ultimate Member &gt; Settings &gt; General &gt; Pages.</strong></p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b4c51e30c1875e8e067575/file-etUumfKj6X.png" alt=""></p><ul><li><p><strong>Stripe Embedded Checkout (Payment Checkout Page)</strong> - By enabling the <strong>&#39;Stripe Embedded Checkout&#39;</strong> feature within the <a href="/docs-v3/um-stripe/article/1886-stripe-settings">Stripe settings</a> , when you click the <strong>&#39;Create pages&#39;</strong> button it&#39;ll automatically generate the <strong>&#39;Payment Checkout page&#39;</strong>. This specialized page is crafted to streamline the transaction process for users, facilitating quick and effortless purchases. Alternatively, if you favor embedding the checkout form directly onto your website, you have the option to enable this setting. Doing so empowers users to finalize their purchases seamlessly without the need to navigate away from your site</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6d5b320e3b82eb738e105/file-bp6tUgIiHT.png" alt=""></p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65c628bb18ce7f6806c755c1/file-wzAdnLpUJY.png" alt=""></p></li></ul><p><strong>NEXT: <a href="/docs-v3/um-stripe/article/1617-create-subscription-prices">Create Subscription Prices</a></strong></p>',4);function b(f,y){const a=r("ExternalLinkIcon");return i(),c("div",null,[p,e("ul",null,[h,e("li",null,[d,t(` This is a dedicated page that's created specifically for the direct customer portal URL, which appears as " `),e("a",u,[t("yoursite.com/customer-portal/"),n(a)]),t(' ". If a user who is logged in attempts to access the page or its URL without actually accessing the page, they will be automatically redirected to the Stripe customer portal site. For more information, read this '),g,t(" .")])]),m])}const S=o(l,[["render",b],["__file","1609-stripe---setting-up-stripe-success-and-cancel-payment-pages.html.vue"]]);export{S as default};
